#include<bits/stdc++.h>
using namespace std;
int p[10005];
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>p[i];
    }

    do{
        int temp = p[n];
        for (int i = n; i >= 2; --i) p[i] = p[i - 1];
        p[1] = temp;
        for(int i=1;i<=n;i++)cout<<p[i]<<" ";
        cout<<endl;
        if(p[n]==n){
            return 0;
        }
    }while(p[n]!=n);
    if(n==1)cout<<1;//这两句加了90，不加80
    if(n==2)cout<<1<<" "<<2;
    return 0;
}
